// src/pages/Clips.jsx
import React, { useState, useEffect, useRef } from 'react';
import Header from '../components/Header';
import './Clips.css';

const Clips = () => {
  const [clips, setClips] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const containerRef = useRef(null);
  const videoRefs = useRef({});

  useEffect(() => {
    // Загружаем клипы напрямую
    fetchClipsDirectly();
  }, []);

  const fetchClipsDirectly = async () => {
    try {
      setLoading(true);

      // Прямой запрос к API
      const response = await fetch('http://127.0.0.1:5000/api/clips/local');

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      }

      const data = await response.json();
      console.log('📦 Получены данные:', data);

      if (!Array.isArray(data) || data.length === 0) {
        setError('Нет видеофайлов в папке static/videos');
        setClips([]);
        return;
      }

      // Добавляем ID и проверяем URL
      const processedClips = data.map((clip, index) => ({
        ...clip,
        id: clip.id || index,
        videoUrl: `http://127.0.0.1:5000${clip.url}` // Полный URL для теста
      }));

      console.log('✅ Обработанные клипы:', processedClips);
      setClips(processedClips);

    } catch (err) {
      console.error('❌ Ошибка загрузки:', err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  // Автовоспроизведение при скролле
  useEffect(() => {
    if (!containerRef.current || clips.length === 0) return;

    const handleScroll = () => {
      const container = containerRef.current;
      const clipHeight = container.clientHeight;
      const scrollTop = container.scrollTop;
      const currentIndex = Math.round(scrollTop / clipHeight);

      // Останавливаем все видео
      Object.values(videoRefs.current).forEach(video => {
        if (video) {
          video.pause();
          video.currentTime = 0;
        }
      });

      // Запускаем текущее видео
      const currentVideo = videoRefs.current[currentIndex];
      if (currentVideo) {
        console.log(`▶️ Воспроизведение клипа ${currentIndex}`);
        currentVideo.currentTime = 0;
        currentVideo.play().catch(err => {
          console.log('Автовоспроизведение заблокировано:', err);
          currentVideo.controls = true;
        });
      }
    };

    const container = containerRef.current;
    container.addEventListener('scroll', handleScroll);

    // Запускаем первое видео
    setTimeout(() => {
      const firstVideo = videoRefs.current[0];
      if (firstVideo) {
        firstVideo.play().catch(err => {
          console.log('Запуск первого видео заблокирован:', err);
        });
      }
    }, 500);

    return () => container.removeEventListener('scroll', handleScroll);
  }, [clips]);

  const setVideoRef = (index, element) => {
    if (element) {
      videoRefs.current[index] = element;
      console.log(`📹 Видео ${index} зарегистрировано`);
    }
  };

  if (loading) {
    return (
      <>
        <Header />
        <div className="flex-center" style={{ height: '80vh', color: '#d47b7b' }}>
          <div>Загрузка клипов...</div>
        </div>
      </>
    );
  }

  if (error) {
    return (
      <>
        <Header />
        <div className="flex-center" style={{ height: '80vh', color: '#d47b7b', flexDirection: 'column' }}>
          <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>⚠️</div>
          <div style={{ marginBottom: '1rem' }}>{error}</div>
          <button 
            onClick={fetchClipsDirectly}
            style={{
              padding: '10px 20px',
              background: '#8b1e1e',
              color: 'white',
              border: 'none',
              borderRadius: '5px',
              cursor: 'pointer'
            }}
          >
            Попробовать снова
          </button>
        </div>
      </>
    );
  }

  return (
    <>
      <Header />
      <div className="clips-container" ref={containerRef}>
        {clips.map((clip, index) => (
          <div key={clip.id} className="clip-item">
            <div className="clip-card">
              <div className="clip-number">#{index + 1}</div>

              <div className="clip-video">
                <video
                  ref={(el) => setVideoRef(index, el)}
                  muted
                  loop
                  playsInline
                  preload="auto"
                  controls
                  style={{
                    width: '100%',
                    height: '100%',
                    objectFit: 'cover',
                    backgroundColor: '#000'
                  }}
                  onError={(e) => {
                    console.error('❌ Ошибка видео:', clip.videoUrl, e);
                    e.target.style.display = 'none';
                    e.target.parentElement.innerHTML = `
                      <div style="color: #d47b7b; text-align: center; padding: 2rem;">
                        <div style="font-size: 2rem;">⚠️</div>
                        <div>Ошибка загрузки видео</div>
                        <div style="font-size: 0.8rem; margin-top: 1rem; color: #8b6b6b;">
                          ${clip.filename}
                        </div>
                      </div>
                    `;
                  }}
                  onLoadedData={() => {
                    console.log('✅ Видео загружено:', clip.filename);
                  }}
                  onCanPlay={() => {
                    console.log('✅ Видео готово к воспроизведению:', clip.filename);
                  }}
                >
                  <source src={clip.videoUrl || clip.url} type={`video/${clip.format}`} />
                  Ваш браузер не поддерживает видео тег.
                </video>
              </div>

              <div className="clip-info">
                <div className="clip-title">{clip.title}</div>
                <div className="clip-description">
                  {clip.size_mb} МБ • Формат: {clip.format}
                  <br />
                  <small style={{ color: '#8b6b6b' }}>{clip.filename}</small>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </>
  );
};

export default Clips;
